vector<int> Solution::memLeak(int memory1, int memory2) {
    int crashTime = 1;
    int memory1Crash = memory1;
    int memory2Crash = memory2;

    while (memory1 > 0 || memory2 > 0) {
        int minMemory = min(memory1, memory2);
        if (memory1 > memory2) {
            memory1 -= minMemory;
        } else {
            memory2 -= minMemory;
        }
        crashTime++;
        if (memory1 == 0) {
            memory1Crash = minMemory;
        }
        if (memory2 == 0) {
            memory2Crash = minMemory;
        }
    }
    return {crashTime, memory1Crash, memory2Crash};
}
```

